import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function queryPhishingDatabase(chainName, suspectedAddress) {
  // Use TransactionService to detect dust-attack patterns (zero-value transfers from unknown)
  const txns = await client.TransactionService.getTransactionsForAddressV3(
    chainName, suspectedAddress, { pageSize: 50 }
  );
  const zeroValueOutgoing = (txns.data?.items ?? []).filter(
    tx => tx.from_address === suspectedAddress && (tx.value ?? "0") === "0"
  );
  const isPhishing = zeroValueOutgoing.length > 10;
  return { suspectedAddress, isPhishing, dustAttacks: zeroValueOutgoing.length };
}
